head.b:skin:
/*=======================================
  CINEMA DARK - Blogger Template
  Dark Movie/Cinema Theme
  Version: 1.0
=======================================*/

/* === CSS Variables === */
:root {
  --bg-primary: #0a0e17;
  --bg-secondary: #111827;
  --bg-card: #1a2236;
  --bg-card-hover: #243049;
  --bg-sidebar: #111827;
  --bg-header: rgba(10, 14, 23, 0.95);
  --bg-footer: #0a0e17;
  --text-primary: #e8eaed;
  --text-secondary: #9ca3af;
  --text-muted: #6b7280;
  --accent-green: #10b981;
  --accent-green-hover: #34d399;
  --accent-blue: #3b82f6;
  --accent-gold: #f59e0b;
  --accent-red: #ef4444;
  --accent-purple: #8b5cf6;
  --border-color: #1f2937;
  --border-light: #374151;
  --shadow-card: 0 4px 20px rgba(0, 0, 0, 0.3);
  --shadow-hover: 0 8px 30px rgba(0, 0, 0, 0.5);
  --shadow-glow: 0 0 20px rgba(16, 185, 129, 0.2);
  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 16px;
  --radius-xl: 20px;
  --transition: all 0.3s ease;
  --max-width: 1200px;
}

/* === Reset & Base === */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: 'Poppins', -apple-system, BlinkMacSystemFont, sans-serif;
  background-color: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.7;
  overflow-x: hidden;
}

a {
  text-decoration: none;
  color: inherit;
  transition: var(--transition);
}

a:hover {
  color: var(--accent-green);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

ul, ol {
  list-style: none;
}

::selection {
  background: var(--accent-green);
  color: #fff;
}

::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: var(--bg-primary);
}

::-webkit-scrollbar-thumb {
  background: var(--bg-card);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--accent-green);
}

/* === Container === */
.container {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 0 20px;
}

/* === Preloader === */
#preloader {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: var(--bg-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 99999;
  transition: opacity 0.5s ease;
}

#preloader.hide {
  opacity: 0;
  pointer-events: none;
}

.loader-spinner {
  width: 50px;
  height: 50px;
  border: 3px solid var(--bg-card);
  border-top: 3px solid var(--accent-green);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

/* === Top Bar === */
.top-bar {
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
  padding: 8px 0;
  font-size: 12px;
}

.top-bar .container {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.top-bar-left {
  display: flex;
  align-items: center;
  gap: 15px;
  color: var(--text-secondary);
}

.top-bar-left i {
  color: var(--accent-green);
  margin-right: 5px;
}

.top-bar-right {
  display: flex;
  align-items: center;
  gap: 12px;
}

.top-bar-right a {
  color: var(--text-secondary);
  font-size: 14px;
  transition: var(--transition);
}

.top-bar-right a:hover {
  color: var(--accent-green);
  transform: translateY(-1px);
}

/* === Header === */
.main-header {
  background: var(--bg-header);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border-color);
  position: sticky;
  top: 0;
  z-index: 1000;
  padding: 15px 0;
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 30px;
}

/* Logo */
.logo {
  flex-shrink: 0;
}

.logo a {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 24px;
  font-weight: 800;
  color: var(--text-primary);
  letter-spacing: -0.5px;
}

.logo-icon {
  width: 42px;
  height: 42px;
  background: linear-gradient(135deg, var(--accent-green), var(--accent-blue));
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 20px;
  color: #fff;
}

.logo span {
  background: linear-gradient(135deg, var(--accent-green), var(--accent-blue));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Search Bar */
.header-search {
  flex: 1;
  max-width: 500px;
}

.search-form {
  display: flex;
  align-items: center;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: 50px;
  overflow: hidden;
  transition: var(--transition);
}

.search-form:focus-within {
  border-color: var(--accent-green);
  box-shadow: var(--shadow-glow);
}

.search-form input {
  flex: 1;
  background: transparent;
  border: none;
  padding: 12px 20px;
  color: var(--text-primary);
  font-family: 'Poppins', sans-serif;
  font-size: 14px;
  outline: none;
}

.search-form input::placeholder {
  color: var(--text-muted);
}

.search-form button {
  background: var(--accent-green);
  border: none;
  padding: 12px 20px;
  color: #fff;
  cursor: pointer;
  font-size: 14px;
  transition: var(--transition);
}

.search-form button:hover {
  background: var(--accent-green-hover);
}

/* Header Actions */
.header-actions {
  display: flex;
  align-items: center;
  gap: 15px;
}

.header-actions a,
.header-actions button {
  color: var(--text-secondary);
  font-size: 18px;
  transition: var(--transition);
  background: none;
  border: none;
  cursor: pointer;
}

.header-actions a:hover,
.header-actions button:hover {
  color: var(--accent-green);
}

/* === Navigation === */
.main-nav {
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
  padding: 0;
  overflow-x: auto;
}

.main-nav::-webkit-scrollbar {
  height: 0;
}

.nav-list {
  display: flex;
  align-items: center;
  gap: 0;
}

.nav-list li a {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 14px 18px;
  color: var(--text-secondary);
  font-size: 13px;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  white-space: nowrap;
  border-bottom: 2px solid transparent;
  transition: var(--transition);
}

.nav-list li a:hover,
.nav-list li a.active {
  color: var(--accent-green);
  border-bottom-color: var(--accent-green);
  background: rgba(16, 185, 129, 0.05);
}

.nav-list li a i {
  font-size: 14px;
}

/* === Featured Slider === */
.featured-section {
  padding: 25px 0;
}

.section-title {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 20px;
  font-size: 20px;
  font-weight: 700;
}

.section-title i {
  color: var(--accent-green);
  font-size: 22px;
}

.section-title::after {
  content: '';
  flex: 1;
  height: 1px;
  background: linear-gradient(to right, var(--border-color), transparent);
}

.slider-container {
  position: relative;
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.slider-wrapper {
  display: flex;
  transition: transform 0.5s ease;
}

.slider-slide {
  min-width: 100%;
  position: relative;
  aspect-ratio: 21/9;
  overflow: hidden;
  border-radius: var(--radius-lg);
}

.slider-slide img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.slider-overlay {
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  padding: 40px 30px 30px;
  background: linear-gradient(to top, rgba(0,0,0,0.95) 0%, rgba(0,0,0,0.6) 50%, transparent 100%);
}

.slider-badge {
  display: inline-block;
  background: var(--accent-green);
  color: #fff;
  padding: 4px 12px;
  border-radius: 50px;
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 10px;
}

.slider-title {
  font-size: 28px;
  font-weight: 800;
  margin-bottom: 8px;
  line-height: 1.3;
}

.slider-meta {
  display: flex;
  align-items: center;
  gap: 15px;
  color: var(--text-secondary);
  font-size: 13px;
  margin-bottom: 10px;
}

.slider-meta span {
  display: flex;
  align-items: center;
  gap: 5px;
}

.slider-meta .star {
  color: var(--accent-gold);
}

.slider-desc {
  color: var(--text-secondary);
  font-size: 14px;
  max-width: 600px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.slider-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: var(--accent-green);
  color: #fff;
  padding: 10px 24px;
  border-radius: 50px;
  font-size: 13px;
  font-weight: 600;
  margin-top: 15px;
  transition: var(--transition);
}

.slider-btn:hover {
  background: var(--accent-green-hover);
  transform: translateY(-2px);
  box-shadow: 0 5px 15px rgba(16, 185, 129, 0.3);
}

.slider-nav {
  position: absolute;
  bottom: 20px;
  right: 30px;
  display: flex;
  gap: 8px;
  z-index: 10;
}

.slider-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: rgba(255,255,255,0.3);
  cursor: pointer;
  transition: var(--transition);
}

.slider-dot.active {
  background: var(--accent-green);
  width: 30px;
  border-radius: 5px;
}

.slider-arrows {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  width: 100%;
  display: flex;
  justify-content: space-between;
  padding: 0 15px;
  z-index: 10;
  pointer-events: none;
}

.slider-arrow {
  width: 40px;
  height: 40px;
  background: rgba(0,0,0,0.5);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  cursor: pointer;
  pointer-events: all;
  transition: var(--transition);
  font-size: 14px;
}

.slider-arrow:hover {
  background: var(--accent-green);
  border-color: var(--accent-green);
}

/* === Main Layout === */
.main-layout {
  display: grid;
  grid-template-columns: 1fr 320px;
  gap: 30px;
  padding: 25px 0;
}

/* === Movie Grid === */
.movie-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 22px;
}

.movie-card {
  background: var(--bg-card);
  border-radius: var(--radius-md);
  overflow: hidden;
  border: 1px solid var(--border-color);
  transition: var(--transition);
  position: relative;
}

.movie-card:hover {
  transform: translateY(-8px);
  box-shadow: var(--shadow-hover);
  border-color: var(--accent-green);
}

.movie-card:hover .movie-poster img {
  transform: scale(1.08);
}

.movie-card:hover .movie-overlay {
  opacity: 1;
}

.movie-poster {
  position: relative;
  aspect-ratio: 2/3;
  overflow: hidden;
}

.movie-poster img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.5s ease;
}

.movie-quality {
  position: absolute;
  top: 10px;
  left: 10px;
  background: var(--accent-green);
  color: #fff;
  padding: 3px 8px;
  border-radius: 4px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.5px;
}

.movie-quality.hd {
  background: var(--accent-blue);
}

.movie-quality.uhd {
  background: var(--accent-purple);
}

.movie-rating-badge {
  position: absolute;
  top: 10px;
  right: 10px;
  background: rgba(0,0,0,0.7);
  backdrop-filter: blur(10px);
  color: var(--accent-gold);
  padding: 4px 10px;
  border-radius: 50px;
  font-size: 12px;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 4px;
}

.movie-rating-badge i {
  font-size: 10px;
}

.movie-overlay {
  position: absolute;
  inset: 0;
  background: rgba(0,0,0,0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: var(--transition);
}

.play-btn {
  width: 55px;
  height: 55px;
  background: var(--accent-green);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-size: 20px;
  transition: var(--transition);
  box-shadow: 0 0 20px rgba(16, 185, 129, 0.4);
}

.play-btn:hover {
  transform: scale(1.1);
  background: var(--accent-green-hover);
}

.movie-info {
  padding: 15px;
}

.movie-title {
  font-size: 14px;
  font-weight: 600;
  margin-bottom: 6px;
  display: -webkit-box;
  -webkit-line-clamp: 1;
  -webkit-box-orient: vertical;
  overflow: hidden;
  line-height: 1.4;
}

.movie-title a:hover {
  color: var(--accent-green);
}

.movie-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  color: var(--text-muted);
  font-size: 12px;
}

.movie-genre {
  color: var(--accent-green);
  font-weight: 500;
}

.movie-year {
  color: var(--text-muted);
}

/* === Movie List Style === */
.movie-list {
  display: flex;
  flex-direction: column;
  gap: 15px;
}

.movie-list-item {
  display: flex;
  gap: 15px;
  background: var(--bg-card);
  border-radius: var(--radius-md);
  overflow: hidden;
  border: 1px solid var(--border-color);
  transition: var(--transition);
}

.movie-list-item:hover {
  border-color: var(--accent-green);
  box-shadow: var(--shadow-card);
}

.movie-list-poster {
  width: 120px;
  min-height: 170px;
  flex-shrink: 0;
  overflow: hidden;
  position: relative;
}

.movie-list-poster img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: var(--transition);
}

.movie-list-item:hover .movie-list-poster img {
  transform: scale(1.05);
}

.movie-list-info {
  padding: 15px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.movie-list-title {
  font-size: 16px;
  font-weight: 600;
  margin-bottom: 6px;
  line-height: 1.4;
}

.movie-list-title a:hover {
  color: var(--accent-green);
}

.movie-list-desc {
  color: var(--text-secondary);
  font-size: 13px;
  margin-bottom: 10px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.movie-list-meta {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 12px;
  color: var(--text-muted);
}

.movie-list-meta .stars {
  color: var(--accent-gold);
  display: flex;
  align-items: center;
  gap: 2px;
}

.movie-list-meta .stars i {
  font-size: 11px;
}

/* === Pagination === */
.pagination {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 30px 0;
}

.pagination a {
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: 40px;
  height: 40px;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-sm);
  color: var(--text-secondary);
  font-size: 14px;
  font-weight: 500;
  transition: var(--transition);
}

.pagination a:hover,
.pagination a.active {
  background: var(--accent-green);
  border-color: var(--accent-green);
  color: #fff;
}

/* === Sidebar === */
.sidebar {
  display: flex;
  flex-direction: column;
  gap: 25px;
}

.sidebar-widget {
  background: var(--bg-card);
  border-radius: var(--radius-md);
  border: 1px solid var(--border-color);
  overflow: hidden;
}

.widget-title {
  padding: 16px 18px;
  font-size: 15px;
  font-weight: 700;
  border-bottom: 1px solid var(--border-color);
  display: flex;
  align-items: center;
  gap: 8px;
}

.widget-title i {
  color: var(--accent-green);
}

.widget-content {
  padding: 15px;
}

/* Genre Tags */
.genre-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.genre-tag {
  display: inline-block;
  padding: 6px 14px;
  background: var(--bg-secondary);
  border: 1px solid var(--border-color);
  border-radius: 50px;
  color: var(--text-secondary);
  font-size: 12px;
  font-weight: 500;
  transition: var(--transition);
}

.genre-tag:hover {
  background: var(--accent-green);
  border-color: var(--accent-green);
  color: #fff;
}

/* Popular Posts Widget */
.popular-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.popular-item {
  display: flex;
  gap: 12px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border-color);
}

.popular-item:last-child {
  border-bottom: none;
  padding-bottom: 0;
}

.popular-num {
  width: 30px;
  height: 30px;
  background: var(--bg-secondary);
  border-radius: var(--radius-sm);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 700;
  color: var(--accent-green);
  flex-shrink: 0;
}

.popular-item:nth-child(1) .popular-num {
  background: var(--accent-green);
  color: #fff;
}

.popular-item:nth-child(2) .popular-num {
  background: var(--accent-blue);
  color: #fff;
}

.popular-item:nth-child(3) .popular-num {
  background: var(--accent-gold);
  color: #fff;
}

.popular-info {
  flex: 1;
}

.popular-info h4 {
  font-size: 13px;
  font-weight: 500;
  line-height: 1.4;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  margin-bottom: 4px;
}

.popular-info h4 a:hover {
  color: var(--accent-green);
}

.popular-info span {
  font-size: 11px;
  color: var(--text-muted);
}

/* Sidebar Ad */
.sidebar-ad {
  background: linear-gradient(135deg, var(--bg-card), var(--bg-secondary));
  border-radius: var(--radius-md);
  padding: 25px;
  text-align: center;
  border: 1px dashed var(--border-light);
}

.sidebar-ad i {
  font-size: 36px;
  color: var(--text-muted);
  margin-bottom: 10px;
}

.sidebar-ad p {
  color: var(--text-muted);
  font-size: 13px;
}

/* === Post Page === */
.post-page {
  padding: 25px 0;
}

.post-single {
  max-width: 850px;
  margin: 0 auto;
}

.post-breadcrumb {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 20px;
  font-size: 13px;
  color: var(--text-muted);
}

.post-breadcrumb a {
  color: var(--accent-green);
}

.post-breadcrumb span {
  color: var(--text-muted);
}

.post-featured-img {
  width: 100%;
  aspect-ratio: 16/9;
  border-radius: var(--radius-lg);
  overflow: hidden;
  margin-bottom: 25px;
}

.post-featured-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.post-content-wrap {
  background: var(--bg-card);
  border-radius: var(--radius-lg);
  border: 1px solid var(--border-color);
  padding: 30px;
}

.post-header-info {
  margin-bottom: 20px;
}

.post-labels {
  display: flex;
  gap: 8px;
  margin-bottom: 12px;
  flex-wrap: wrap;
}

.post-label {
  padding: 4px 12px;
  background: rgba(16, 185, 129, 0.1);
  border: 1px solid rgba(16, 185, 129, 0.3);
  border-radius: 50px;
  font-size: 11px;
  font-weight: 600;
  color: var(--accent-green);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.post-title-single {
  font-size: 28px;
  font-weight: 800;
  line-height: 1.3;
  margin-bottom: 12px;
}

.post-meta-bar {
  display: flex;
  align-items: center;
  gap: 20px;
  color: var(--text-secondary);
  font-size: 13px;
  flex-wrap: wrap;
}

.post-meta-bar span {
  display: flex;
  align-items: center;
  gap: 6px;
}

.post-meta-bar i {
  color: var(--accent-green);
}

/* Star Rating in Post */
.post-rating {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 15px 0;
  padding: 12px 16px;
  background: rgba(245, 158, 11, 0.1);
  border-radius: var(--radius-sm);
  border: 1px solid rgba(245, 158, 11, 0.2);
}

.post-rating .stars {
  color: var(--accent-gold);
  font-size: 16px;
  display: flex;
  gap: 2px;
}

.post-rating .rating-num {
  font-weight: 700;
  color: var(--accent-gold);
  font-size: 16px;
}

.post-rating .rating-text {
  color: var(--text-secondary);
  font-size: 13px;
}

/* Post Body */
.post-body {
  font-size: 15px;
  line-height: 1.9;
  color: var(--text-secondary);
}

.post-body h2 {
  font-size: 22px;
  font-weight: 700;
  color: var(--text-primary);
  margin: 25px 0 12px;
}

.post-body h3 {
  font-size: 18px;
  font-weight: 600;
  color: var(--text-primary);
  margin: 20px 0 10px;
}

.post-body p {
  margin-bottom: 16px;
}

.post-body img {
  border-radius: var(--radius-md);
  margin: 15px 0;
}

.post-body a {
  color: var(--accent-green);
  text-decoration: underline;
}

.post-body ul, .post-body ol {
  margin: 10px 0 16px 20px;
}

.post-body li {
  margin-bottom: 6px;
}

.post-body blockquote {
  border-left: 3px solid var(--accent-green);
  padding: 15px 20px;
  margin: 16px 0;
  background: var(--bg-secondary);
  border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
  font-style: italic;
}

.post-body pre, .post-body code {
  background: var(--bg-secondary);
  border-radius: var(--radius-sm);
  font-size: 13px;
}

.post-body code {
  padding: 2px 6px;
}

.post-body pre {
  padding: 16px;
  overflow-x: auto;
}

/* Movie Info Box */
.movie-info-box {
  background: var(--bg-secondary);
  border-radius: var(--radius-md);
  padding: 20px;
  margin: 20px 0;
  border: 1px solid var(--border-color);
}

.movie-info-box h3 {
  font-size: 16px;
  font-weight: 700;
  margin-bottom: 15px;
  color: var(--accent-green);
  display: flex;
  align-items: center;
  gap: 8px;
}

.info-row {
  display: flex;
  padding: 8px 0;
  border-bottom: 1px solid var(--border-color);
  font-size: 13px;
}

.info-row:last-child {
  border-bottom: none;
}

.info-row .label {
  width: 120px;
  color: var(--text-muted);
  font-weight: 500;
  flex-shrink: 0;
}

.info-row .value {
  color: var(--text-primary);
}

/* Download Box */
.download-box {
  background: linear-gradient(135deg, rgba(16, 185, 129, 0.1), rgba(59, 130, 246, 0.1));
  border-radius: var(--radius-md);
  padding: 25px;
  margin: 25px 0;
  border: 1px solid rgba(16, 185, 129, 0.3);
  text-align: center;
}

.download-box h3 {
  font-size: 20px;
  font-weight: 700;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
}

.download-box h3 i {
  color: var(--accent-green);
}

.download-box p {
  color: var(--text-secondary);
  font-size: 14px;
  margin-bottom: 20px;
}

.download-links {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  justify-content: center;
}

.download-btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 28px;
  border-radius: 50px;
  font-size: 14px;
  font-weight: 600;
  transition: var(--transition);
  color: #fff;
}

.download-btn.primary {
  background: var(--accent-green);
}

.download-btn.secondary {
  background: var(--accent-blue);
}

.download-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 5px 15px rgba(0,0,0,0.3);
}

.download-btn.primary:hover {
  background: var(--accent-green-hover);
}

/* Share Buttons */
.share-box {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-top: 25px;
  padding-top: 20px;
  border-top: 1px solid var(--border-color);
}

.share-box span {
  font-weight: 600;
  font-size: 14px;
  color: var(--text-primary);
}

.share-btn {
  width: 38px;
  height: 38px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-size: 14px;
  transition: var(--transition);
}

.share-btn.facebook { background: #1877f2; }
.share-btn.twitter { background: #1da1f2; }
.share-btn.telegram { background: #0088cc; }
.share-btn.whatsapp { background: #25d366; }
.share-btn.pinterest { background: #e60023; }

.share-btn:hover {
  transform: translateY(-2px);
  opacity: 0.9;
}

/* Related Posts */
.related-section {
  margin-top: 30px;
}

.related-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 15px;
  margin-top: 15px;
}

.related-card {
  background: var(--bg-card);
  border-radius: var(--radius-sm);
  overflow: hidden;
  border: 1px solid var(--border-color);
  transition: var(--transition);
}

.related-card:hover {
  border-color: var(--accent-green);
  transform: translateY(-3px);
}

.related-card-img {
  aspect-ratio: 16/9;
  overflow: hidden;
}

.related-card-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: var(--transition);
}

.related-card:hover .related-card-img img {
  transform: scale(1.05);
}

.related-card-info {
  padding: 12px;
}

.related-card-info h4 {
  font-size: 13px;
  font-weight: 500;
  line-height: 1.4;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.related-card-info h4 a:hover {
  color: var(--accent-green);
}

/* === Comments === */
.comments-section {
  margin-top: 30px;
  background: var(--bg-card);
  border-radius: var(--radius-md);
  border: 1px solid var(--border-color);
  padding: 25px;
}

.comments-section h3 {
  font-size: 18px;
  font-weight: 700;
  margin-bottom: 20px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.comments-section h3 i {
  color: var(--accent-green);
}

/* === Footer === */
.main-footer {
  background: var(--bg-footer);
  border-top: 1px solid var(--border-color);
  padding: 40px 0 0;
  margin-top: 40px;
}

.footer-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 30px;
  padding-bottom: 30px;
}

.footer-col h4 {
  font-size: 16px;
  font-weight: 700;
  margin-bottom: 18px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.footer-col h4 i {
  color: var(--accent-green);
}

.footer-about p {
  color: var(--text-secondary);
  font-size: 13px;
  line-height: 1.8;
  margin-bottom: 15px;
}

.footer-social {
  display: flex;
  gap: 10px;
}

.footer-social a {
  width: 36px;
  height: 36px;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
  font-size: 14px;
  transition: var(--transition);
}

.footer-social a:hover {
  background: var(--accent-green);
  border-color: var(--accent-green);
  color: #fff;
}

.footer-links li {
  margin-bottom: 8px;
}

.footer-links li a {
  color: var(--text-secondary);
  font-size: 13px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.footer-links li a:hover {
  color: var(--accent-green);
  padding-left: 5px;
}

.footer-links li a i {
  font-size: 8px;
  color: var(--accent-green);
}

.footer-contact li {
  display: flex;
  align-items: flex-start;
  gap: 10px;
  margin-bottom: 12px;
  color: var(--text-secondary);
  font-size: 13px;
}

.footer-contact li i {
  color: var(--accent-green);
  margin-top: 3px;
}

.footer-bottom {
  border-top: 1px solid var(--border-color);
  padding: 18px 0;
  text-align: center;
}

.footer-bottom p {
  color: var(--text-muted);
  font-size: 12px;
}

.footer-bottom a {
  color: var(--accent-green);
  font-weight: 500;
}

/* === Back to Top === */
.back-to-top {
  position: fixed;
  bottom: 30px;
  right: 30px;
  width: 45px;
  height: 45px;
  background: var(--accent-green);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #fff;
  font-size: 16px;
  cursor: pointer;
  opacity: 0;
  visibility: hidden;
  transition: var(--transition);
  z-index: 999;
  box-shadow: 0 4px 15px rgba(16, 185, 129, 0.3);
}

.back-to-top.visible {
  opacity: 1;
  visibility: visible;
}

.back-to-top:hover {
  background: var(--accent-green-hover);
  transform: translateY(-3px);
}

/* === Responsive === */
@media (max-width: 1024px) {
  .main-layout {
    grid-template-columns: 1fr;
  }

  .sidebar {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
  }

  .movie-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .footer-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 768px) {
  .top-bar {
    display: none;
  }

  .header-inner {
    flex-wrap: wrap;
  }

  .header-search {
    order: 3;
    max-width: 100%;
    width: 100%;
    margin-top: 10px;
  }

  .nav-list li a {
    padding: 12px 14px;
    font-size: 12px;
  }

  .slider-title {
    font-size: 20px;
  }

  .movie-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 12px;
  }

  .sidebar {
    grid-template-columns: 1fr;
  }

  .footer-grid {
    grid-template-columns: 1fr;
  }

  .post-title-single {
    font-size: 22px;
  }

  .related-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .container {
    padding: 0 15px;
  }
}

@media (max-width: 480px) {
  .movie-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 10px;
  }

  .movie-info {
    padding: 10px;
  }

  .movie-title {
    font-size: 12px;
  }

  .post-content-wrap {
    padding: 18px;
  }

  .related-grid {
    grid-template-columns: 1fr;
  }

  .download-links {
    flex-direction: column;
  }

  .download-btn {
    width: 100%;
    justify-content: center;
  }
}

/* === Animations === */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.movie-card {
  animation: fadeInUp 0.5s ease forwards;
}

.movie-card:nth-child(2) { animation-delay: 0.1s; }
.movie-card:nth-child(3) { animation-delay: 0.2s; }
.movie-card:nth-child(4) { animation-delay: 0.3s; }
.movie-card:nth-child(5) { animation-delay: 0.4s; }
.movie-card:nth-child(6) { animation-delay: 0.5s; }

/* === Blogger Default Overrides === */
.blog-posts .post-outer-container {
  margin-bottom: 0;
}

.post-outer, .post {
  background: none !important;
  border: none !important;
  padding: 0 !important;
}

.post-body img {
  background: none;
  border: none;
  padding: 0;
}

#comments {
  background: none;
}

.widget ul {
  list-style: none;
}

/* Mobile Menu Toggle */
.mobile-menu-btn {
  display: none;
  background: none;
  border: none;
  color: var(--text-primary);
  font-size: 22px;
  cursor: pointer;
  padding: 5px;
}

@media (max-width: 768px) {
  .mobile-menu-btn {
    display: block;
  }

  .main-nav {
    display: none;
  }

  .main-nav.active {
    display: block;
  }

  .nav-list {
    flex-direction: column;
  }

  .nav-list li a {
    border-bottom: 1px solid var(--border-color);
    width: 100%;
    padding: 12px 18px;
  }
}

/* Status Message */
.status-msg-wrap {
  margin: 15px 0;
  padding: 12px 18px;
  background: rgba(16, 185, 129, 0.1);
  border: 1px solid rgba(16, 185, 129, 0.3);
  border-radius: var(--radius-sm);
  color: var(--accent-green);
  font-size: 14px;
}

body.script:
//

// Preloader
window.addEventListener('load', function() {
  var preloader = document.getElementById('preloader');
  if (preloader) {
    preloader.classList.add('hide');
    setTimeout(function() {
      preloader.style.display = 'none';
    }, 500);
  }
});

// Mobile Menu Toggle
var mobileMenuBtn = document.getElementById('mobileMenuBtn');
var mainNav = document.getElementById('mainNav');
if (mobileMenuBtn && mainNav) {
  mobileMenuBtn.addEventListener('click', function() {
    mainNav.classList.toggle('active');
  });
}

// Back to Top
var backToTop = document.getElementById('backToTop');
if (backToTop) {
  window.addEventListener('scroll', function() {
    if (window.pageYOffset > 300) {
      backToTop.classList.add('visible');
    } else {
      backToTop.classList.remove('visible');
    }
  });
  backToTop.addEventListener('click', function(e) {
    e.preventDefault();
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
}

// Current Year
var yearEl = document.getElementById('currentYear');
if (yearEl) {
  yearEl.textContent = new Date().getFullYear();
}

// Simple Auto Slider
var slideIndex = 0;
var sliderWrapper = document.getElementById('sliderWrapper');
var slides = document.querySelectorAll('.slider-slide');

function showSlides() {
  if (slides.length > 1 && sliderWrapper) {
    slideIndex++;
    if (slideIndex >= slides.length) {
      slideIndex = 0;
    }
    sliderWrapper.style.transform = 'translateX(-' + (slideIndex * 100) + '%)';
  }
}

if (slides.length > 1) {
  setInterval(showSlides, 5000);
}

// Star Rating from post title (customization)
// If you want to add custom ratings per post, use labels like "Rating-8.5"
document.querySelectorAll('.movie-card').forEach(function(card) {
  var labels = card.querySelectorAll('.movie-genre a');
  labels.forEach(function(label) {
    if (label.textContent.indexOf('Rating-') !== -1) {
      var rating = label.textContent.replace('Rating-', '');
      var badge = card.querySelector('.movie-rating-badge');
      if (badge) {
        badge.innerHTML = '<i class="fas fa-star"/> ' + rating;
      }
    }
  });
});

// Related Posts (simple - load based on labels)
if (document.getElementById('relatedPosts')) {
  var labels = document.querySelectorAll('.post-label');
  if (labels.length > 0) {
    var firstLabel = labels[0].getAttribute('href');
    if (firstLabel) {
      fetch(firstLabel + '?max-results=3&alt=json')
        .then(function(res) { return res.json(); })
        .then(function(data) {
          var container = document.getElementById('relatedPosts');
          if (data.feed && data.feed.entry) {
            var html = '';
            data.feed.entry.forEach(function(entry) {
              var title = entry.title.$t;
              var link = '';
              var img = 'https://via.placeholder.com/400x225/1a2236/10b981?text=Movie';
              entry.link.forEach(function(l) {
                if (l.rel === 'alternate') link = l.href;
              });
              if (entry.media$thumbnail) {
                img = entry.media$thumbnail.url.replace('/s72-c/', '/w400-h225-c/');
              }
              if (link && title) {
                html += '<div class="related-card"><div class="related-card-img"><img alt="' + title + '" src="' + img + '"/></div><div class="related-card-info"><h4><a href="' + link + '">' + title + '</a></h4></div></div>';
              }
            });
            container.innerHTML = html;
          }
        })
        .catch(function() {});
    }
  }
}

//
